def sign_xml_element(element):
    """Sign an XML element using XML Digital Signature with SHA-256."""
    private_key_pem = cert_manager.get_private_key_pem()
    certificate_pem = cert_manager.get_certificate_pem()

    signer = XMLSigner(
        method=XMLSigner.SignatureConstructionMethod.enveloped,
        signature_algorithm="rsa-sha256",
        digest_algorithm="sha256",
        c14n_algorithm="http://www.w3.org/2001/10/xml-exc-c14n#",
    )

    signed_element = signer.sign(
        element,
        key=private_key_pem,
        cert=certificate_pem,
    )

    return signed_element


def authenticate_user(username, password):
    """Authenticate a user against the internal user store."""
    if not username or not password:
        return None

    # Prevent timing attacks by always doing the hash comparison
    user = USERS.get(username)
    if user is None:
        # Hash the password anyway to prevent timing-based user enumeration
        hash_password(password)
        return None

    if verify_password(user["password_hash"], password):
        return {
            "username": username,
            "email": user["email"],
            "first_name": user["first_name"],
            "last_name": user["last_name"],
            "roles": user["roles"],
        }

    return None


