@app.route('/saml/sso', methods=['GET', 'POST'])
def sso():
    """Handle SAML SSO requests (both GET and POST bindings)."""

    saml_request = None
    relay_state = None

    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest')
        relay_state = request.args.get('RelayState')
    elif request.method == 'POST':
        saml_request = request.form.get('SAMLRequest')
        relay_state = request.form.get('RelayState')

    if not saml_request:
        abort(400, description="Missing SAMLRequest parameter")

    # Parse the AuthnRequest
    authn_request, error = parse_authn_request(saml_request)
    if error:
        abort(400, description=f"Invalid AuthnRequest: {error}")

    # Validate the SP
    sp_entity_id = authn_request["issuer"]
    acs_url = authn_request.get("acs_url")

    # If no ACS URL in request, use the registered one
    if not acs_url:
        valid, result = validate_sp(sp_entity_id)
        if not valid:
            abort(403, description=result)
        acs_url = result["acs_url"]
        sp_name = result["name"]
    else:
        valid, result = validate_sp(sp_entity_id, acs_url)
        if not valid:
            abort(403, description=result)
        sp_name = result["name"]

    # Store SAML request info in session
    session['saml_request'] = {
        'id': authn_request['id'],
        'sp_entity_id': sp_entity_id,
        'acs_url': acs_url,
        'relay_state': relay_state,
        'sp_name': sp_name,
        'timestamp': datetime.datetime.utcnow().isoformat(),
    }

    # Check if user is already authenticated
    if 'user' in session:
        # Validate session hasn't expired
        session_created = session.get('session_created')
        if session_created:
            created_time = datetime.datetime.fromisoformat(session_created)
            if (datetime.datetime.utcnow() - created_time).total_seconds() > 28800:  # 8 hours
                session.pop('user', None)
                session.pop('session_created', None)
            else:
                return generate_saml_response_and_redirect()

    # Show login form
    csrf_token = generate_csrf_token()
    return render_template_string(
        LOGIN_TEMPLATE,
        sp_name=sp_name,
        error=None,
        action_url="/saml/login",
        csrf_token=csrf_token,
    )


@app.route('/saml/login', methods=['POST'])
def login():
    """Handle login form submission."""

    # Validate CSRF token
    csrf_token = request.form.get('csrf_token')
    if not validate_csrf_token(csrf_token):
        abort(403, description="Invalid CSRF token")

    saml_request_info = session.get('saml_request')
    if not saml_request_info:
        abort(400, description="No pending SAML request")

    # Check if the SAML request is still fresh (max 5 minutes)
    request_time = datetime.datetime.fromisoformat(saml_request_info['timestamp'])
    if (datetime.datetime.utcnow() - request_time).total_seconds() > 300:
        session.pop('saml_request', None)
        abort(400, description="SAML request has expired")

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')

    # Input validation
    if not username or not password:
        csrf_token = generate_csrf_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            sp_name=saml_request_info.get('sp_name', ''),
            error="Username and password are required",
            action_url="/saml/login",
            csrf_token=csrf_token,
        ), 401

    # Validate username format (alphanumeric only, max 64 chars)
    if len(username) > 64 or not username.replace('_', '').replace('-', '').replace('.', '').isalnum():
        csrf_token = generate_csrf_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            sp_name=saml_request_info.get('sp_name', ''),
            error="Invalid credentials",
            action_url="/saml/login",
            csrf_token=csrf_token,
        ), 401

    user_info = authenticate_user(username, password)
    if not user_info:
        csrf_token = generate_csrf_token()
        return render_template_string(
            LOGIN_TEMPLATE,
            sp_name=saml_request_info.get('sp_name', ''),
            error="Invalid credentials",
            action_url="/saml/login",
            csrf_token=csrf_token,
        ), 401

    # Store user in session
    session['user'] = user_info
    session['session_created'] = datetime.datetime.utcnow().isoformat()

    # Regenerate session ID after successful authentication to prevent session fixation
    session.modified = True

    return generate_saml_response_and_redirect()


def generate_saml_response_and_redirect():
    """Generate SAML response and redirect to SP's ACS URL."""

    user_info = session.get('user')
    saml_request_info = session.get('saml_request')

    if not user_info or not saml_request_info:
        abort(400, description="Missing session data")

    sp_entity_id = saml_request_info['sp_entity_id']
    acs_url = saml_request_info['acs_url']
    in_response_to = saml_request_info.get('id')
    relay_state = saml_request_info.get('relay_state')

    # Re-validate SP and ACS URL before generating response
    valid, result = validate_sp(sp_entity_id, acs_url)
    if not valid:
        abort(403, description=result)

    # Build and sign the SAML response
    saml_response_xml = build_saml_response(
        user_info=user_info,
        sp_entity_id=sp_entity_id,
        acs_url=acs_url,
        in_response_to=in_response_to,
    )

    # Base64 encode the response
    saml_response_b64 = base64.b64encode(saml_response_xml).decode('utf-8')

    # Clean up the SAML request from session
    session.pop('saml_request', None)

    # Return POST binding form
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=acs_url,
        saml_response=saml_response_b64,
        relay_state=relay_state,
    )


