def create_ssl_context():
    """Create an SSL context for HTTPS."""
    ssl_context = ssl.SSLContext(ssl.PROTOCOL_TLS_SERVER)
    ssl_context.minimum_version = ssl.TLSVersion.TLSv1_2
    ssl_context.set_ciphers(
        'ECDHE+AESGCM:ECDHE+CHACHA20:DHE+AESGCM:DHE+CHACHA20:!aNULL:!MD5:!DSS:!RC4'
    )

    ssl_cert_path = os.path.join("certs", "server_cert.pem")
    ssl_key_path = os.path.join("certs", "server_key.pem")

    if os.path.exists(ssl_cert_path) and os.path.exists(ssl_key_path):
        ssl_context.load_cert_chain(ssl_cert_path, ssl_key_path)
    else:
        # For development, use the IdP cert (in production, use a proper TLS cert)
        ssl_context.load_cert_chain(
            cert_manager.certificate_path,
            cert_manager.private_key_path,
        )

    return ssl_context


